{
  "name": "Aços Vital - Soluções em Aço",
  "description": "Website institucional moderno para a Aços Vital, apresentando catálogo de produtos siderúrgicos, serviços especializados e um consultor técnico inteligente baseado em IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  category: string;
  description: string;
  image: string;
  features: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export enum SteelCategory {
  SHEETS = 'Chapas',
  TUBES = 'Tubos',
  BARS = 'Barras',
  PROFILES = 'Perfis',
  SPECIAL = 'Especiais'
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

const SYSTEM_INSTRUCTION = `
Você é o Assistente Técnico Virtual da Aços Vital, uma empresa líder no setor siderúrgico.
Seu objetivo é ajudar engenheiros, construtores e compradores a escolherem os melhores materiais de aço.
Você deve falar em Português do Brasil.
Seja profissional, técnico e prestativo.
Conhecimento base: 
- Chapas (Galvanizadas, Pretas, Xadrez)
- Tubos (Quadrados, Redondos, Retangulares)
- Perfis (U, I, W, Dobrados)
- Barras (Chatas, Redondas, Quadradas, Cantoneiras)
Se perguntarem algo fora de siderurgia, responda gentilmente que seu foco é em soluções de aço.
Não invente preços, diga que para orçamentos devem entrar em contato com a equipe comercial através do formulário.
`;

export const getGeminiResponse = async (history: ChatMessage[], message: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    // We don't use history in the simple version, or we can map history to contents if needed.
    // For this implementation, we'll use a direct prompt with context.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });

    return response.text || "Desculpe, tive um problema ao processar sua solicitação.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Lamento, o serviço de consultoria está temporariamente indisponível.";
  }
};

import React, { useState, useEffect } from 'react';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-white shadow-md py-2' : 'bg-transparent py-4'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center">
            <div className="flex-shrink-0 flex items-center gap-2">
              <div className="bg-orange-600 p-2 rounded-lg">
                <i className="fas fa-industry text-white text-2xl"></i>
              </div>
              <span className={`text-2xl font-oswald font-bold tracking-tighter ${isScrolled ? 'text-slate-900' : 'text-white'}`}>
                AÇOS <span className="text-orange-600">VITAL</span>
              </span>
            </div>
          </div>

          <div className="hidden md:block">
            <div className="ml-10 flex items-baseline space-x-8">
              {['Início', 'Produtos', 'Serviços', 'Consultoria AI', 'Contato'].map((item) => (
                <a
                  key={item}
                  href={`#${item.toLowerCase().replace(' ', '-')}`}
                  className={`px-3 py-2 text-sm font-medium transition-colors ${isScrolled ? 'text-slate-600 hover:text-orange-600' : 'text-slate-100 hover:text-orange-400'}`}
                >
                  {item}
                </a>
              ))}
              <button className="bg-orange-600 hover:bg-orange-700 text-white px-5 py-2 rounded-full font-semibold text-sm transition-transform active:scale-95">
                SOLICITAR ORÇAMENTO
              </button>
            </div>
          </div>

          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className={`${isScrolled ? 'text-slate-900' : 'text-white'} p-2`}
            >
              <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'} text-2xl`}></i>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-white shadow-xl animate-fade-in-down">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {['Início', 'Produtos', 'Serviços', 'Consultoria AI', 'Contato'].map((item) => (
              <a
                key={item}
                href={`#${item.toLowerCase().replace(' ', '-')}`}
                className="text-slate-900 block px-3 py-4 text-base font-medium border-b border-slate-100 last:border-0"
                onClick={() => setIsMenuOpen(false)}
              >
                {item}
              </a>
            ))}
            <div className="p-3">
              <button className="w-full bg-orange-600 text-white py-3 rounded-lg font-bold">
                SOLICITAR ORÇAMENTO
              </button>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React from 'react';
