export default ProductCard;

import React, { useState, useRef, useEffect } from 'react';
import { getGeminiResponse } from '../services/geminiService';
import { ChatMessage } from '../types';

const AIConsultant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Olá! Sou o Consultor Técnico da Aços Vital. Como posso ajudar você hoje com seus materiais siderúrgicos?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    const response = await getGeminiResponse(messages, userMsg);

    setMessages(prev => [...prev, { role: 'model', text: response }]);
    setIsLoading(false);
  };

  return (
    <section id="consultoria-ai" className="py-24 bg-slate-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col lg:flex-row gap-12 items-center">
          <div className="lg:w-1/2">
            <span className="text-orange-500 font-bold tracking-widest text-sm uppercase">Tecnologia de Ponta</span>
            <h2 className="text-4xl md:text-5xl font-oswald text-white font-bold mt-4 mb-6 uppercase">
              CONSULTORIA TÉCNICA <br />
              <span className="text-orange-600">INTELIGENTE</span>
            </h2>
            <p className="text-slate-400 text-lg mb-8 leading-relaxed">
              Dúvidas sobre qual bitola utilizar? Qual o melhor tipo de aço para ambiente corrosivo? 
              Nossa IA técnica está pronta para responder suas dúvidas em tempo real com base em normas técnicas e conhecimento especializado.
            </p>
            <div className="space-y-4">
              <div className="flex items-start gap-4">
                <div className="bg-orange-600/20 p-3 rounded-lg">
                  <i className="fas fa-bolt text-orange-500 text-xl"></i>
                </div>
                <div>
                  <h4 className="text-white font-bold">Resposta Instantânea</h4>
                  <p className="text-slate-500 text-sm">Disponível 24/7 para suporte técnico imediato.</p>
                </div>
              </div>
              <div className="flex items-start gap-4">
                <div className="bg-orange-600/20 p-3 rounded-lg">
                  <i className="fas fa-microchip text-orange-500 text-xl"></i>
                </div>
                <div>
                  <h4 className="text-white font-bold">Baseada em Dados Reais</h4>
                  <p className="text-slate-500 text-sm">Informações precisas baseadas em manuais técnicos.</p>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full">
            <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden flex flex-col h-[500px] shadow-2xl">
              {/* Header */}
              <div className="p-4 bg-slate-700/50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-orange-600 rounded-full flex items-center justify-center text-white relative">
                    <i className="fas fa-robot"></i>
                    <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-slate-800 rounded-full"></div>
                  </div>
                  <div>
                    <h5 className="text-white text-sm font-bold">Vital AI Assistant</h5>
                    <p className="text-slate-400 text-[10px] uppercase tracking-wider">Online agora</p>
                  </div>
                </div>
                <button className="text-slate-400 hover:text-white"><i className="fas fa-cog"></i></button>
              </div>

              {/* Chat Area */}
              <div ref={scrollRef} className="flex-grow overflow-y-auto p-6 space-y-4 scroll-smooth">
                {messages.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[80%] p-4 rounded-2xl text-sm ${
                      msg.role === 'user' 
                      ? 'bg-orange-600 text-white rounded-tr-none' 
                      : 'bg-slate-700 text-slate-200 rounded-tl-none'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start">
                    <div className="bg-slate-700 text-slate-200 p-4 rounded-2xl rounded-tl-none flex gap-2">
                      <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                      <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-100"></div>
                      <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-200"></div>
                    </div>
                  </div>
                )}
              </div>

              {/* Input */}
              <div className="p-4 bg-slate-900 border-t border-slate-700">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="Pergunte sobre normas, tipos de aço..."
                    className="flex-grow bg-slate-800 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:border-orange-600 transition-colors"
                  />
                  <button 
                    onClick={handleSend}
                    className="bg-orange-600 hover:bg-orange-700 text-white p-3 rounded-xl transition-all active:scale-95 disabled:opacity-50"
                    disabled={isLoading}
                  >
