}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage } from "../types";

const SYSTEM_INSTRUCTION = `
Você é o Assistente Técnico Virtual da Aços Vital, referência em soluções siderúrgicas para indústria e construção.
Seu objetivo é ajudar engenheiros, construtores, caldeireiros e compradores a escolherem os melhores materiais de aço.
Você deve falar em Português do Brasil.
Seja profissional, técnico, preciso e prestativo.
Conhecimento base atualizado: 
- Chapas (Galvanizadas, Pretas, Xadrez, Grossas, ASTM A36)
- Tubos (Quadrados, Redondos, Retangulares, com e sem costura, NBR 5580, NBR 5590)
- Perfis (U, I, W, Dobrados, Cantoneiras)
- Flanges (SO, WN, Blind, ANSI, DIN)
- Conexões (Tupy, Curvas, Tês, Reduções)
- Válvulas (Gaveta, Globo, Borboleta, Retenção)
- Serviços: Oxicorte, Corte e Dobra, Caldeiraria.

Se perguntarem algo fora de siderurgia ou materiais industriais, responda gentilmente que seu foco é em soluções de aço e materiais industriais para a Aços Vital.
Não invente preços. Diga que para orçamentos precisos eles devem preencher o formulário no site ou entrar em contato via WhatsApp para falar com o time comercial.
Mencione que a Aços Vital possui certificações de qualidade (ISO 9001) e cadastro CRC Petrobras quando relevante para reforçar autoridade.
`;

export const getGeminiResponse = async (history: ChatMessage[], message: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });

    return response.text || "Desculpe, tive um problema ao processar sua solicitação.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Lamento, o serviço de consultoria está temporariamente indisponível.";
  }
};

