// Fix: Updated to follow @google/genai guidelines and correctly incorporate conversation history
export const getGeminiResponse = async (history: ChatMessage[], message: string): Promise<string> => {
  // Use a named parameter for the API key as required by the SDK and use process.env.API_KEY directly.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Transform conversation history into the contents array format required for multi-turn generation.
    const contents = history.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    // Add the current user message to the context for the model.
    contents.push({
      role: 'user',
      parts: [{ text: message }]
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });

    // Access the .text property directly as it is a getter on the response object.
    return response.text || "Desculpe, tive um problema ao processar sua solicitação.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Lamento, o serviço de consultoria está temporariamente indisponível.";
  }
};

