import React, { useState, useEffect } from 'react';
import { Calculator, Scale, Info } from 'lucide-react';
import { SteelType, ShapeType, CalculationResult } from '../types';

const DENSITIES = {
  [SteelType.CARBON]: 7.85,
  [SteelType.STAINLESS]: 8.0,
  [SteelType.ALUMINUM]: 2.7,
};

const WeightCalculator: React.FC = () => {
  const [material, setMaterial] = useState<SteelType>(SteelType.CARBON);
  const [shape, setShape] = useState<ShapeType>(ShapeType.SHEET);
  const [dim1, setDim1] = useState<number>(0); // Largura ou Diâmetro (mm)
  const [dim2, setDim2] = useState<number>(0); // Comprimento (mm)
  const [thickness, setThickness] = useState<number>(0); // Espessura (mm)
  const [result, setResult] = useState<number | null>(null);

  const calculate = () => {
    let weight = 0;
    const density = DENSITIES[material];

    if (shape === ShapeType.SHEET) {
      // Peso = (Largura/1000) * (Comprimento/1000) * Espessura * Densidade
      weight = (dim1 / 1000) * (dim2 / 1000) * thickness * density;
    } else if (shape === ShapeType.TUBE_ROUND) {
      // Peso linear aprox: (OD - WT) * WT * 0.02466 (para carbono)
      // Usando densidade genérica: PI * (RaioExt^2 - RaioInt^2) * Comprimento * Densidade
      const outerRadius = dim1 / 2;
      const innerRadius = outerRadius - thickness;
      const area = Math.PI * (Math.pow(outerRadius, 2) - Math.pow(innerRadius, 2));
      weight = (area / 1000000) * dim2 * density;
    } else {
      // Perfil genérico para fins ilustrativos
      weight = (dim1 * thickness * 2 + dim2 * thickness) * (1 / 1000000) * 1000 * density;
    }

    setResult(weight > 0 ? weight : null);
  };

  useEffect(() => {
    calculate();
  }, [material, shape, dim1, dim2, thickness]);

  return (
    <section id="calculadora" className="py-24 bg-brand-blue-secondary relative overflow-hidden">
