                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Material</label>
                  <select 
                    value={material} 
                    onChange={(e) => setMaterial(e.target.value as SteelType)}
                    className="w-full bg-brand-blue-secondary text-white px-4 py-3 rounded-xl border border-white/10 focus:border-brand-orange outline-none"
                  >
                    {Object.values(SteelType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Formato</label>
                  <select 
                    value={shape} 
