            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-brand-blue-secondary p-6 rounded-2xl border border-white/5 group hover:border-brand-orange/30 transition-all">
                <div className="bg-brand-orange/10 w-12 h-12 rounded-xl flex items-center justify-center mb-4">
                  <Zap className="text-brand-orange w-6 h-6" />
                </div>
                <h4 className="text-white font-bold mb-2">Respostas Ágeis</h4>
                <p className="text-slate-500 text-sm">Informações sobre bitolas, pressões e materiais instantaneamente.</p>
              </div>
              <div className="bg-brand-blue-secondary p-6 rounded-2xl border border-white/5 group hover:border-brand-orange/30 transition-all">
                <div className="bg-brand-orange/10 w-12 h-12 rounded-xl flex items-center justify-center mb-4">
                  <ShieldCheck className="text-brand-orange w-6 h-6" />
                </div>
                <h4 className="text-white font-bold">Normas Técnicas</h4>
                <p className="text-slate-500 text-sm">Orientação baseada em NBR, ASTM, ANSI e normas Petrobras.</p>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full">
            <div className="bg-brand-blue-secondary rounded-[2.5rem] border border-white/10 overflow-hidden flex flex-col h-[600px] shadow-2xl relative">
              <div className="absolute inset-0 bg-brand-orange/5 pointer-events-none"></div>

              <div className="p-6 bg-white/5 backdrop-blur-md flex items-center justify-between border-b border-white/10 relative z-10">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-brand-orange rounded-2xl flex items-center justify-center text-white shadow-lg shadow-brand-orange/20">
                    <Bot className="w-7 h-7" />
                  </div>
                  <div>
                    <h5 className="text-white text-base font-bold">Vital AI Consultant</h5>
                    <div className="flex items-center gap-1.5">
                      <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                      <p className="text-slate-400 text-[10px] uppercase tracking-wider font-bold">Ativo agora</p>
                    </div>
                  </div>
                </div>
              </div>

              <div ref={scrollRef} className="flex-grow overflow-y-auto p-8 space-y-6 scroll-smooth relative z-10">
                {messages.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} items-start gap-3`}>
                    {msg.role === 'model' && (
                      <div className="w-8 h-8 rounded-full bg-brand-orange/20 flex items-center justify-center shrink-0 border border-brand-orange/20">
                        <Bot className="w-4 h-4 text-brand-orange" />
                      </div>
                    )}
                    <div className={`max-w-[85%] p-5 rounded-2xl text-sm leading-relaxed ${
                      msg.role === 'user' 
                      ? 'bg-brand-orange text-white rounded-tr-none shadow-lg' 
                      : 'bg-white/5 text-slate-200 border border-white/10 rounded-tl-none'
                    }`}>
                      {msg.text}
                      <div className={`text-[8px] mt-2 opacity-50 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                        {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </div>
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start items-start gap-3">
                    <div className="w-8 h-8 rounded-full bg-brand-orange/20 flex items-center justify-center shrink-0">
                      <Bot className="w-4 h-4 text-brand-orange" />
                    </div>
                    <div className="bg-white/5 border border-white/10 p-5 rounded-2xl rounded-tl-none flex gap-1.5">
                      <div className="w-1.5 h-1.5 bg-brand-orange rounded-full animate-bounce"></div>
                      <div className="w-1.5 h-1.5 bg-brand-orange rounded-full animate-bounce delay-150"></div>
                      <div className="w-1.5 h-1.5 bg-brand-orange rounded-full animate-bounce delay-300"></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="p-6 bg-brand-blue-dark border-t border-white/10 relative z-10">
                <div className="flex gap-3">
                  <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="Ex: Qual chapa usar para oxicorte?"
                    className="flex-grow bg-white/5 text-white px-6 py-4 rounded-2xl border border-white/10 focus:outline-none focus:border-brand-orange focus:ring-1 focus:ring-brand-orange transition-all placeholder:text-slate-600"
                  />
                  <button 
                    onClick={handleSend}
                    className="bg-brand-orange hover:bg-brand-orange-dark text-white p-4 rounded-2xl transition-all active:scale-95 disabled:opacity-50 shadow-lg shadow-brand-orange/20"
                    disabled={isLoading}
                  >
                    <Send className="w-6 h-6" />
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default AIConsultant;

